package inequivalent;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

class ClonePair88Method1Test {

    private final ClonePair88 subject = new ClonePair88();

    @Test
    void method1FindsLastOccurrenceIgnoringCase() {
        // Generated by Codex (gpt-5.4).
        char[] source = "abRaCadABRA".toCharArray();
        char[] target = "ABRA".toCharArray();

        assertEquals(7, subject.method1(source, 0, source.length, target, 0, target.length, source.length));
    }

    @Test
    void method1ReturnsMinusOneForNegativeFromIndex() {
        // Generated by Codex (gpt-5.4).
        char[] source = "hello".toCharArray();
        char[] target = "lo".toCharArray();

        assertEquals(-1, subject.method1(source, 0, source.length, target, 0, target.length, -1));
    }

    @Test
    void method1ClampsFromIndexWhenItIsLargerThanRightMostStart() {
        // Generated by Codex (gpt-5.4).
        char[] source = "hello".toCharArray();
        char[] target = "ll".toCharArray();

        assertEquals(2, subject.method1(source, 0, source.length, target, 0, target.length, 99));
    }

    @Test
    void method1ReturnsClampedFromIndexForEmptyTarget() {
        // Generated by Codex (gpt-5.4).
        char[] source = "hello".toCharArray();
        char[] target = "x".toCharArray();

        assertEquals(5, subject.method1(source, 0, source.length, target, 0, 0, 99));
    }

    @Test
    void method1ThrowsNullPointerExceptionWhenSourceIsNullAndSearchMustProceed() {
        // Generated by Codex (gpt-5.4).
        char[] target = "he".toCharArray();

        assertThrows(NullPointerException.class, () -> subject.method1(null, 0, 3, target, 0, target.length, 0));
    }
}
